79	// Capabilities returns the capabilities that the model supports
80	func (m *Model) Capabilities() []model.Capability {
81		capabilities := []model.Capability{}
82	
83		if m.ModelPath != "" {
84			f, err := gguf.Open(m.ModelPath)
85			if err == nil {
86				defer f.Close()
87	
88				if f.KeyValue("pooling_type").Valid() {
89					capabilities = append(capabilities, model.CapabilityEmbedding)
90				} else {
91					// If no embedding is specified, we assume the model supports completion
92					capabilities = append(capabilities, model.CapabilityCompletion)
93				}
94				if f.KeyValue("vision.block_count").Valid() {
95					capabilities = append(capabilities, model.CapabilityVision)
96				}
97				if f.KeyValue("audio.block_count").Valid() {
98					capabilities = append(capabilities, model.CapabilityAudio)
99				}
100			} else {
101				slog.Error("couldn't open model file", "error", err)
102			}
103		}
104	
105		// Also include capabilities from the model config (e.g. vision capability
106		// set during creation for MLX/safetensors models).
107		if len(m.Config.Capabilities) > 0 {
108			for _, c := range m.Config.Capabilities {
109				cap := model.Capability(c)
110				if !slices.Contains(capabilities, cap) {
111					capabilities = append(capabilities, cap)
112				}
113			}
114		}
115	
116		if len(capabilities) == 0 {
117			slog.Warn("unknown capabilities for model", "model", m.Name)
118		}
119	
120		if m.Template == nil {
121			return capabilities
122		}
123	
124		builtinParser := parsers.ParserForName(m.Config.Parser)
125		// Check for tools capability
126		v, err := m.Template.Vars()
127		if err != nil {
128			slog.Warn("model template contains errors", "error", err)
129		}
130		if slices.Contains(v, "tools") || (builtinParser != nil && builtinParser.HasToolSupport()) {
131			capabilities = append(capabilities, model.CapabilityTools)
132		}
133	
134		// Check for insert capability
135		if slices.Contains(v, "suffix") {
136			capabilities = append(capabilities, model.CapabilityInsert)
137		}
138	
139		// Check for vision capability in projector-based models
140		if len(m.ProjectorPaths) > 0 {
141			capabilities = append(capabilities, model.CapabilityVision)
142		}
143	
144		// Skip the thinking check if it's already set
145		if slices.Contains(capabilities, "thinking") {
146			return capabilities
147		}
148	
149		// Check for thinking capability
150		openingTag, closingTag := thinking.InferTags(m.Template.Template)
151		hasTags := openingTag != "" && closingTag != ""
152		isGptoss := slices.Contains([]string{"gptoss", "gpt-oss"}, m.Config.ModelFamily)
153		if hasTags || isGptoss || (builtinParser != nil && builtinParser.HasThinkingSupport()) {
154			capabilities = append(capabilities, model.CapabilityThinking)
155		}
156	
157		// Temporary workaround — suppress vision/audio for gemma4 MLX models
158		// until multimodal runtime pipeline lands. Remove when imageproc.go is wired up.
159		if m.Config.ModelFormat == "safetensors" && m.Config.Renderer == "gemma4" {
160			capabilities = slices.DeleteFunc(capabilities, func(c model.Capability) bool {
161				return c == model.CapabilityVision || c == "audio"
162			})
163		}
164	
165		return capabilities
166	}
