57	func (l *inferenceRequestLogger) middleware(route string) gin.HandlerFunc {
58		return func(c *gin.Context) {
59			if c.Request == nil {
60				c.Next()
61				return
62			}
63	
64			method := c.Request.Method
65			host := c.Request.Host
66			scheme := "http"
67			if c.Request.TLS != nil {
68				scheme = "https"
69			}
70			contentType := c.GetHeader("Content-Type")
71	
72			var body []byte
73			if c.Request.Body != nil {
74				var err error
75				body, err = io.ReadAll(c.Request.Body)
76				c.Request.Body = io.NopCloser(bytes.NewReader(body))
77				if err != nil {
78					slog.Warn("failed to read request body for debug logging", "route", route, "error", err)
79				}
80			}
81	
82			c.Next()
83			l.log(route, method, scheme, host, contentType, body)
84		}
85	}
