87	func (l *inferenceRequestLogger) log(route, method, scheme, host, contentType string, body []byte) {
88		if l == nil || l.dir == "" {
89			return
90		}
91	
92		if contentType == "" {
93			contentType = "application/json"
94		}
95		if host == "" || scheme == "" {
96			base := envconfig.Host()
97			if host == "" {
98				host = base.Host
99			}
100			if scheme == "" {
101				scheme = base.Scheme
102			}
103		}
104	
105		routeForFilename := sanitizeRouteForFilename(route)
106		timestamp := fmt.Sprintf("%s-%06d", time.Now().UTC().Format("20060102T150405.000000000Z"), atomic.AddUint64(&l.counter, 1))
107		bodyFilename := fmt.Sprintf("%s_%s_body.json", timestamp, routeForFilename)
108		curlFilename := fmt.Sprintf("%s_%s_request.sh", timestamp, routeForFilename)
109		bodyPath := filepath.Join(l.dir, bodyFilename)
110		curlPath := filepath.Join(l.dir, curlFilename)
111	
112		if err := os.WriteFile(bodyPath, body, 0o600); err != nil {
113			slog.Warn("failed to write debug request body", "route", route, "error", err)
114			return
115		}
116	
117		url := fmt.Sprintf("%s://%s%s", scheme, host, route)
118		curl := fmt.Sprintf("#!/bin/sh\nSCRIPT_DIR=\"$(CDPATH= cd -- \"$(dirname -- \"$0\")\" && pwd)\"\ncurl --request %s --url %q --header %q --data-binary @\"${SCRIPT_DIR}/%s\"\n", method, url, "Content-Type: "+contentType, bodyFilename)
119		if err := os.WriteFile(curlPath, []byte(curl), 0o600); err != nil {
120			slog.Warn("failed to write debug request replay command", "route", route, "error", err)
121			return
122		}
123	
124		slog.Info(fmt.Sprintf("logged to %s, replay using curl with `sh %s`", bodyPath, curlPath))
125	}
126	
127	func sanitizeRouteForFilename(route string) string {
128		route = strings.TrimPrefix(route, "/")
129		if route == "" {
130			return "root"
131		}
132	
133		var b strings.Builder
134		b.Grow(len(route))
135		for _, r := range route {
136			if ('a' <= r && r <= 'z') || ('A' <= r && r <= 'Z') || ('0' <= r && r <= '9') {
137				b.WriteRune(r)
138			} else {
139				b.WriteByte('_')
140			}
141		}
142	
143		return b.String()
144	}
