1027	// getExistingName searches the models directory for the longest prefix match of
1028	// the input name and returns the input name with all existing parts replaced
1029	// with each part found. If no parts are found, the input name is returned as
1030	// is.
1031	func getExistingName(n model.Name) (model.Name, error) {
1032		var zero model.Name
1033		existing, err := manifest.Manifests(true)
1034		if err != nil {
1035			return zero, err
1036		}
1037		var set model.Name // tracks parts already canonicalized
1038		for e := range existing {
1039			if set.Host == "" && strings.EqualFold(e.Host, n.Host) {
1040				n.Host = e.Host
1041			}
1042			if set.Namespace == "" && strings.EqualFold(e.Namespace, n.Namespace) {
1043				n.Namespace = e.Namespace
1044			}
1045			if set.Model == "" && strings.EqualFold(e.Model, n.Model) {
1046				n.Model = e.Model
1047			}
1048			if set.Tag == "" && strings.EqualFold(e.Tag, n.Tag) {
1049				n.Tag = e.Tag
1050			}
1051		}
1052		return n, nil
1053	}
