72	func NewLayerFromLayer(digest, mediatype, from string) (Layer, error) {
73		if digest == "" {
74			return Layer{}, errors.New("creating new layer from layer with empty digest")
75		}
76	
77		blob, err := BlobsPath(digest)
78		if err != nil {
79			return Layer{}, err
80		}
81	
82		fi, err := os.Stat(blob)
83		if err != nil {
84			return Layer{}, err
85		}
86	
87		return Layer{
88			MediaType: mediatype,
89			Digest:    digest,
90			Size:      fi.Size(),
91			From:      from,
92			Status:    fmt.Sprintf("using existing layer %s", digest),
93		}, nil
94	}
