96	func (l *Layer) Open() (io.ReadSeekCloser, error) {
97		if l.Digest == "" {
98			return nil, errors.New("opening layer with empty digest")
99		}
100	
101		blob, err := BlobsPath(l.Digest)
102		if err != nil {
103			return nil, err
104		}
105	
106		return os.Open(blob)
107	}
