109	func (l *Layer) Remove() error {
110		if l.Digest == "" {
111			return nil
112		}
113	
114		// Ignore corrupt manifests to avoid blocking deletion of layers that are freshly orphaned
115		ms, err := Manifests(true)
116		if err != nil {
117			return err
118		}
119	
120		for _, m := range ms {
121			for _, layer := range append(m.Layers, m.Config) {
122				if layer.Digest == l.Digest {
123					// something is using this layer
124					return nil
125				}
126			}
127		}
128	
129		blob, err := BlobsPath(l.Digest)
130		if err != nil {
131			return err
132		}
133	
134		return os.Remove(blob)
135	}
