	launch.DefaultConfirmPrompt = func(prompt string) (bool, error) {
		ok, err := tui.RunConfirm(prompt)
		if errors.Is(err, tui.ErrCancelled) {
			return false, launch.ErrCancelled
		}
		return ok, err
	}
}

